INSERT INTO public.photos VALUES (25354, 'Teatro Parisiana 1929', 'Imagen capturada en el interior del antiguo Teatro Parisiana, con un colectivo posado de la compaâ”œâ–’â”œÂ¡a de teatro formada recientemente por Irene Alba y Joaquâ”œÂ¡n Garcâ”œÂ¡a Leâ”œâ”‚n, caracterizada para la representaciâ”œâ”‚n de la obra "Ramo de locura", escrita por los hermanos Serafâ”œÂ¡n y Joaquâ”œÂ¡n â”œÃ¼lvarez Quintero. Figuran, de izquierda a derecha, y de arriba a abajo, Joaquâ”œÂ¡n Garcâ”œÂ¡a Leâ”œâ”‚n, Marâ”œÂ¡a Pujol, Marcial Manent, Pablo Hidalgo, Mercedes Prendes, Irene Alba, Valentina Iparraguirre, Julia Caba y Emilio Gutiâ”œÂ®rrez Esteban. Algunas de las mâ”œÃ­s que notables figuras del pasado, presente, y futuro de la escena espaâ”œâ–’ola. El Teatro Parisiana estaba ubicado en el paseo de la Independencia nâ”¬â•‘ 23, con acceso secundario por la calle de Felipe Sanclemente. En 1934 fue derribado y sustituido por un nuevo recinto de espectâ”œÃ­culos que abriâ”œâ”‚ sus puertas en 1935 con la denominaciâ”œâ”‚n "Nuevo Teatro Parisiana", hasta que en 1938 fue obligado a espaâ”œâ–’olizar su nombre cuando los niâ”œâ–’os ya no venâ”œÂ¡an de Parâ”œÂ¡s, sino de Berlâ”œÂ¡n. Desde entonces, y hasta su definitivo cierre a finales de los aâ”œâ–’os ochenta del pasado siglo, fue el Teatro Argensola. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65011800, -0.88238100, '0101000020E6100000AB933314773CECBF3D450E1137D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34418514784.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34418514784.webp', 'https://www.flickr.com/photos/zaragozaantigua/34418514784/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25356, 'P.â”¬â•‘ Independencia 1935', 'Imagen capturada durante el desfile militar incluido en el programa de actos de homenaje al aniversario IV de la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica. La castrense muestra se realizâ”œâ”‚ sobre un recorrido que se iniciaba en la Gran Vâ”œÂ¡a, seguâ”œÂ¡a por la plaza de Aragâ”œâ”‚n, paseo de la Independencia, plaza de la Constituciâ”œâ”‚n, Coso, calle del Conde Aranda, y finalizaba en la plaza del Portillo. En ella participaron fuerzas de la guarniciâ”œâ”‚n (infanterâ”œÂ¡a, carros de combate, artilleâ”¼Ã²â”œÂ¡a, zapadores, caballerâ”œÂ¡a, pontoneros, intendencia, sanidad), Guardia civil, Fuerzas de Seguridad y Asalto, y Cruz Roja. En la imagen, mientras desfilan tropas del regimiento nâ”¬â•‘ 5 de infanterâ”œÂ¡a, y a la izquierda, la tribuna de autoridades e invitados instalada en la plaza de Santa Engracia. Fuente visual: www.mecd.gob.es/.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64958900, -0.88341100, '0101000020E61000002AA73D25E744ECBFB16B7BBB25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36146755940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36146755940.webp', 'https://www.flickr.com/photos/zaragozaantigua/36146755940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25359, 'P.â”¬â•‘ de la Independencia 1935', 'Imagen capturada en el paseo de la Independencia durante la conmemoraciâ”œâ”‚n oficial del 4.â”¬â•‘ aniversario de la proclamaciâ”œâ”‚n de la Segunda Repâ”œâ•‘blica espaâ”œâ–’ola, con fuerzas de la guarniciâ”œâ”‚n de Zaragoza desfilando en el tramo del paseo entre la calle de Jerâ”œâ”‚nimo Zurita y la plaza de Santa Engracia. Fuente visual: diario grâ”œÃ­fico Ahora (Madrid).', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.65027000, -0.88257400, '0101000020E6100000D09849D40B3EECBFF3C81F0C3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38732093190.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38732093190.webp', 'https://www.flickr.com/photos/zaragozaantigua/38732093190/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25371, 'Pâ”¬â•‘. Independencia c.1935', 'Imagen capturada en el interior de la zona de porches del gran inmueble del nâ”¬â•‘ 30-32 del paseo de la Independencia (actual nâ”¬â•‘ 34), donde desde 1881 estaba ubicado el Gran Cafâ”œÂ® Ambos Mundos, que aquâ”œÂ¡ presenta su acristalada fachada de casi 40 metros de largo, e ingreso principal. Los grandes ventanales, que aquâ”œÂ¡ aparecen decorados con grandes maceteros, permitâ”œÂ¡an un importante acceso de luz natural para tan grande espacio interior con capacidad de hasta 1.800 personas... Fue finalmente cerrado en 1955. Desde 1889 las plantas superiores estaban ocupadas por el Banco de Crâ”œÂ®dito de Zaragoza, desde 1928 remodeladas en profundidad por el arquitecto Pascual Bravo Sanfeliâ”œâ•‘.', 1935, 1935, 1935, 'Anos 30', 'CENTRO', 41.64939400, -0.88427000, '0101000020E610000079AF5A99F04BECBFFC1BB4571FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51375214938.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51375214938.webp', 'https://www.flickr.com/photos/zaragozaantigua/51375214938/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25372, 'P.â”¬â•‘ de la Independencia 1956', 'Imagen capturada una fresca maâ”œâ–’ana de invierno en el paseo de la Independencia y a la altura de la plaza de Santa Engracia durante el trâ”œÃ­nsito de una singular caravana comercial de "Mistol", formada por motocicleta, utilitario, furgoneta y camioneta, recorriendo el centro de la ciudad para promocionar el consumo de este producto. Al fondo, el esquinero edificio de Correos y telâ”œÂ®grafos. En primer tâ”œÂ®rmino, adoquinado y vâ”œÂ¡as del tranvâ”œÂ¡a por donde circulaban las lâ”œÂ¡nea 5. "Venecia-Delicias", 11. "Parque" y 15. "Casablanca".', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.64960300, -0.88331500, '0101000020E6100000A31EA2D11D44ECBF1631EC3026D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51674469989.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51674469989.webp', 'https://www.flickr.com/photos/zaragozaantigua/51674469989/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25375, 'P.â”¬â•‘ de la Independencia c.1957', 'Imagen desde cierta altura del arbolado bulevar de toda la vida del paseo de la Independencia orientado hacia su arranque desde la plaza de Espaâ”œâ–’a, al fondo. A la derecha, ingreso a la plaza de Santa Engracia y edificio de Correos. Sobre el firme de la izquierda, coche de la serie 200 en servicio en la tranviaria lâ”œÂ¡nea 11, Parque encaminado hacia la terminal sita en la plaza del Emperador Carlos V.', 1957, 1957, 1957, 'Anos 50', 'CENTRO', 41.64953000, -0.88371200, '0101000020E6100000E8A562635E47ECBFACE28DCC23D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54166363679.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54166363679.webp', 'https://www.flickr.com/photos/zaragozaantigua/54166363679/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25809, 'Calle San Miguel 1973', 'Esta fue durante 75 aâ”œâ–’os la esquina del Teatro Circo entre las calles de San Miguel y la de los Sitios (luego, Isaac Peral). Tras su demoliciâ”œâ”‚n en 1962, formâ”œâ”‚ parte de un moderno edificio, el actual, en cuyos bajos se instalâ”œâ”‚ la sucursal de una entidad local de ahorro. En el corporativo y acristalado chaflâ”œÃ­n, destellean desde la otra esquina de la calle de San Miguel, unos casuales reflejos del cine Goya, vecino del Teatro Circo durante casi treinta aâ”œâ–’os. Ninguno de los perdura. La sucursal, sâ”œÂ¡. Como bien dice el comercial de la imagen, que nuestros ingresos tienen premios bien lo saben las entidades de depâ”œâ”‚sito de ahorro. Abrumadoramente, para ellas, aunque te seâ”œâ–’alen con el dedo. Fuente visual: Gerardo Sancho Ramo, Archivo Municipal de Zaragoza.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.65087900, -0.88040700, '0101000020E6100000516C054D4B2CECBF9C53C90050D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25263114185.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25263114185.webp', 'https://www.flickr.com/photos/zaragozaantigua/25263114185/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25602, 'Perico Fernâ”œÃ­ndez y Pelâ”œÂ® 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 03/09/1974. "Fâ”œâ•‘tbol. Zaragoza 2 - Santos de Brasil 3." Un partido amistoso de fâ”œâ•‘tbol jugado en el estadio municipal de la Romareda, entre los clubs del "Real Zaragoza" y el "Santos de Brasil", el 3 se setiembre de 1974. En la imagen, saque de honor a cargo de Perico Fernâ”œÃ­ndez, campeâ”œâ”‚n mundial de boxeo en la categorâ”œÂ¡a de pesos ligeros de ese aâ”œâ–’o. A su derecha, Edson Arantes do Nascimento, mâ”œÃ­s conocido como Pelâ”œÂ®.', 1974, 1974, 1974, 'Anos 70', 'UNIVERSIDAD', 41.63664600, -0.90197300, '0101000020E610000011001C7BF6DCECBF8A90BA9D7DD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15126488940.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15126488940.webp', 'https://www.flickr.com/photos/zaragozaantigua/15126488940/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25813, 'Teatro Circo 1895', 'Espectacular imagen capturada tras el incendio del Teatro Circo de febrero de 1895. Inaugurado en octubre de 1887 con diseâ”œâ–’o del arquitecto Ricardo Magdalena Tabuenca, fue construido sobre un solar hasta entonces ocupado por unos lavaderos pâ”œâ•‘blicos. Este incendio devastâ”œâ”‚ el teatro, aunque afortunadamente el siniestro tuvo lugar fuera del horario de funciones y no produjo daâ”œâ–’os personales. Su propietario, Manuel Marraco Rocatallada, pudo reconstruirlo inmediatamente gracias al dinero del seguro, de forma que para las Fiestas del Pilar de ese mismo aâ”œâ–’o el Teatro Circo ya pudo reabrirse al pâ”œâ•‘blico. La instantâ”œÃ­nea recoge el estado de su devastado interior tras el incendio, destacando en la parte superior el esqueleto de la armadura de hierro del techo. A la izquierda, restos del escenario, y a la derecha, de la platea y anfiteatro. En primer tâ”œÂ®rmino, el patio de butaca consumido por el fuego. Al fondo y a la derecha emerge la chimenea de la Electro Peral Zaragozana, instalada desde 1893 en el original Teatro Goya de Zaragoza (1882-1893), y recayente a un vial que conducâ”œÂ¡a a la Huerta de Santa Engracia y que aâ”œâ–’os despuâ”œÂ®s recibirâ”œÂ¡a el nombre de Isaac Peral por la presencia de esta elâ”œÂ®ctrica instalaciâ”œâ”‚n. El singular hallazgo de la original y fracturada placa fotogrâ”œÃ­fica de cristal de esta imagen, restaurada por Julio Sâ”œÃ­nchez Millâ”œÃ­n, ha permitido datar correctamente esta fotografâ”œÂ¡a, hasta ahora asociada al derribo del Teatro Circo en 1962.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.65079700, -0.88044000, '0101000020E61000003FE3C281902CECBFDEAAEB504DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50082592023.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50082592023.webp', 'https://www.flickr.com/photos/zaragozaantigua/50082592023/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25865, 'Teatro Pignatelli 1878', 'Vista del Teatro Pignatelli, en la calle de la Independencia. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1878, 1878, 1878, 'Siglo XIX', 'CENTRO', 41.64979500, -0.88326100, '0101000020E6100000D7A19A92AC43ECBF5A0D897B2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26796673113.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26796673113.webp', 'https://www.flickr.com/photos/zaragozaantigua/26796673113/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25920, 'P.â”¬â•‘ de la Independencia c.1952', 'Imagen capturada desde cierta altura, posiblemente desde el edificio de Correos, de la solana del antiguo paseo de la Independencia, desde el emboque a la calle del Marquâ”œÂ®s de Casa Jimâ”œÂ®nez, y hasta la plaza de Espaâ”œâ–’a, al fondo, a la derecha. A la izquierda, el bloque del nâ”¬â•‘ 30, sede del Banco Central. Inmediato, y en el paseo, el quiosco Pâ”œâ”‚rtico, con publicidad del prestigioso producto "Libel" de Jabones Barangâ”œÂ®, para el "lavado perfecto de prendas finas". Encaminado hacia la plaza de Aragâ”œâ”‚n, una de las primeras unidades de la serie 200, en servicio en la tranviaria lâ”œÂ¡nea Parque. Al otro lado del paseo, una composiciâ”œâ”‚n tranviaria posiblemente transita desde Venecia hacia Delicias. Fuente visual: Editorial Garcâ”œÂ¡a Garrabella, en www.todocoleccion.net/', 1952, 1952, 1952, 'Anos 50', 'CENTRO', 41.64951900, -0.88354300, '0101000020E6100000E48233F8FB45ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31769085620.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31769085620.webp', 'https://www.flickr.com/photos/zaragozaantigua/31769085620/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23266, 'El Portillo 1808', '"Combate de las zaragozanas con los dragones franceses. En el ataque del 15 de Junio 200 dragones franceses pudieron penetrar en la Ciudad y fueron rechazados y muertos por el pueblo. Cinco de ellos, que van a escaparse por la puerta del Portillo, son embestidos por un tropel de Mujeres valientes y perecen a sus manos". Serie Ruinas de Zaragoza, de Juan Gâ”œÃ­lvez (dibujo) y Fernando Brambila (grabado), Câ”œÃ­diz, 1812. Momento en que cinco dragones (soldados de la caballerâ”œÂ¡a francesa con coraza, sable y penacho en la cabeza) que habâ”œÂ¡an entrado por la Puerta del Carmen, intentan escapar cuando caen en que con cinco no van muy lejos, y son atacados por una desmesurada cantidad de zaragozanas en la desaparecida plaza del Portillo. Esta acciâ”œâ”‚n se desarrollâ”œâ”‚ el 15 de junio de 1808. Fuente visual: bvpb.mcu.es/', 1808, 1808, 1808, 'Siglo XIX', 'CENTRO', 41.65581700, -0.89219100, '0101000020E61000001C23D923D48CECBF9694BBCFF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15080217829.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15080217829.webp', 'https://www.flickr.com/photos/zaragozaantigua/15080217829/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23933, 'Plaza de Toros 1904', 'Plaza de Toros de Zaragoza en 1904. Sobresalen por detrâ”œÃ­s las torres y la câ”œâ•‘pula de la iglesia de la Casa de la Misericordia. Fuente: Revista "La fiesta nacional", Barcelona, 1904.', 1904, 1904, 1904, 'Anos 1900', 'CENTRO', 41.65491600, -0.89129900, '0101000020E6100000DFA3FE7A8585ECBF46D09849D4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24431350312.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24431350312.webp', 'https://www.flickr.com/photos/zaragozaantigua/24431350312/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23938, 'Plaza de Toros c.1964', 'Vista de la Plaza de Toros de La Misericordia en la plaza del Portillo. Al fondo, torres y câ”œâ•‘pula de la iglesia del Hogar Pignatelli. Fuente: Foto para postal de Comercial Josan. Cesiâ”œâ”‚n de la familia de Josâ”œÂ® Marâ”œÂ¡a Sanz Gonzâ”œÃ­lez a Rafael Castillejo. Dataciâ”œâ”‚n y procesado:', 1964, 1964, 1964, 'Anos 60', 'CENTRO', 41.65492400, -0.89209200, '0101000020E610000051BEA085048CECBFC9AEB48CD4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27418455015.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27418455015.webp', 'https://www.flickr.com/photos/zaragozaantigua/27418455015/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23948, 'El Portillo c.1903', 'Imagen capturada desde la altura de la iglesia de Nâ”¬Â¬. Sâ”¬Â¬. del Portillo y centrada en la zona del antiguo Campo del Toro, donde destaca el coso de la Misericordia con su aspecto previo a la gran remodelaciâ”œâ”‚n de 1916. A su derecha, la Casa Inclusa y el cuartel de caballerâ”œÂ¡a del Cid. A la izquierda, arranque de la calle de Ramâ”œâ”‚n Pignatelli desde la plaza del Portillo. De fondo, la gran estructura del Hospicio Provincial, del que emergen las torrecillas y la neobizantina câ”œâ•‘pula de su iglesia.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.65496600, -0.89195200, '0101000020E6100000E141B3EBDE8AECBFF8FE06EDD5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51461673787.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51461673787.webp', 'https://www.flickr.com/photos/zaragozaantigua/51461673787/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20889, 'Anfiteatro siglo I', 'Mapa de situaciâ”œâ”‚n del anfiteatro romano de Zaragoza, construido en el siglo I de nuestra Era, segâ”œâ•‘n Miguel Beltrâ”œÃ­n, director del Museo de Zaragoza, 2009. La ubicaciâ”œâ”‚n propuesta tiene como centro actual el Hotel Palafox y estâ”œÃ­ ubicada entre las calles Antonio Valcarreres, Marceliano Isâ”œÃ­bal, Bilbao, Albareda y avenida Câ”œÂ®sar Augusto. Sin embargo, un artâ”œÂ¡culo de 2012 (www.academia.edu/3687122/Una_nueva_hip%C3%B3tesis_sobre_l...) situaba el anfiteatro en la actual plaza de los Sitios, hipâ”œâ”‚tesis que fue rechazada por algâ”œâ•‘n experto aduciendo restos de construcciones de la Exposiciâ”œâ”‚n Hispano Francesa de 1908. Ver plano de situaciâ”œâ”‚n alternativo aquâ”œÂ¡: www.flickr.com/photos/zaragozaantigua/15906334241/. En el estudio "Nuevas cuestiones sobre el anfiteatro de Zaragoza" (2016), de Josâ”œÂ® David Mendoza: www.um.es/cepoat/pantarei/wp-content/uploads/2016/10/pant..., se descartan ambas ubicaciones. Fuente: www.heraldo.es/noticias/cultura/el_anfiteatro_cesaraugust...', 50, NULL, 99, 'Siglo XIX', 'CENTRO', 41.65045600, -0.88550200, '0101000020E6100000EA5C514A0856ECBF55BE672442D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15725380705.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15725380705.webp', 'https://www.flickr.com/photos/zaragozaantigua/15725380705/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21014, 'Monumento a Pignatelli 1867', '"Monumento a Pignatelli", xilografâ”œÂ¡a de Tomâ”œÃ­s Carlos Capuz incluida en la Crâ”œâ”‚nica general de Espaâ”œâ–’a, Madrid, 1867.', 1867, 1867, 1867, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18911975194.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18911975194.webp', 'https://www.flickr.com/photos/zaragozaantigua/18911975194/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21019, 'Exposiciâ”œâ”‚n Aragonesa 1868', '"Exposiciâ”œâ”‚n aragonesa. Proyecto del edificio principal y de disposiciâ”œâ”‚n de las demâ”œÃ­s dependencias". Mariano Utrilla, Zaragoza, 1868. Plano de la Exposiciâ”œâ”‚n Aragonesa de 1868 en Zaragoza, en la Glorieta de Pignatelli. Se celebrâ”œâ”‚ de septiembre a noviembre. Fuente: AMZ.', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19634933925.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19634933925.webp', 'https://www.flickr.com/photos/zaragozaantigua/19634933925/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21036, 'Exposiciâ”œâ”‚n Aragonesa 1868', 'La Sociedad Econâ”œâ”‚mica Aragonesa de Amigos del Paâ”œÂ¡s organizâ”œâ”‚ en 1868 la Exposiciâ”œâ”‚n Aragonesa de Agricultura, la Industria y las Artes, en la Glorieta de Pignatelli de Zaragoza. En la imagen, placa de bronce de 24 cm, conmemorativa del evento. Fuente: www.todocoleccion.net', 1868, 1868, 1868, 'Siglo XIX', 'CENTRO', 41.64845800, -0.88489700, '0101000020E61000002C836A831351ECBF2F6AF7AB00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30709917382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30709917382.webp', 'https://www.flickr.com/photos/zaragozaantigua/30709917382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21056, 'Ramâ”œâ”‚n Pignatelli c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y Câ”œÂ¡a. 1860-1886. "Estatua de Pignatelli". Glorieta de Pignatelli.. Ramâ”œâ”‚n Pignatelli (1734-1793), polâ”œÂ¡tico zaragozano ilustrado, impulsor del Canal Imperial de Aragâ”œâ”‚n.', 1877, 1877, 1877, 'Siglo XIX', 'CENTRO', 41.64830400, -0.88486000, '0101000020E6100000E23B31EBC550ECBFD9EE1EA0FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14864310894.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14864310894.webp', 'https://www.flickr.com/photos/zaragozaantigua/14864310894/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21146, 'Capitanâ”œÂ¡a General 1893', 'AHPZ. Estudio Coyne. 1893. "Capitanâ”œÂ¡a General." Entre 1879 y 1893 se levantâ”œâ”‚ en la Glorieta de Pignatelli el nuevo edificio de la Capitanâ”œÂ¡a General, que se trasladâ”œâ”‚ a esta ubicaciâ”œâ”‚n de la anterior en que estaba, en un antiguo palacio dieciochesco del Coso Medio.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64816800, -0.88569700, '0101000020E61000003C4A253CA157ECBF2828452BF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208551974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208551974.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208551974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21189, 'Plaza de Aragâ”œâ”‚n 1893', 'Inâ”œÂ®dita y luminosa imagen de la plaza de Aragâ”œâ”‚n capturada desde la relativa altura del reciâ”œÂ®n inaugurado "Nuevo Palacio para Capitanâ”œÂ¡a general de Aragâ”œâ”‚n" (sic). En primer tâ”œÂ®rmino y a la izquierda, vâ”œÂ¡as de la lâ”œÂ¡nea de Torrero de la red tranviaria de tracciâ”œâ”‚n animal, en este caso las encaminadas hacia la Playa de Torrero. En el centro de la frondosa plaza, el Monumento a Pignatelli, y de fondo edilicio, las fachadas principales de los orientales hotelitos de los nâ”œâ•‘meros 1 a 7 de la plaza, con una muestra de su aspecto casi original, luego bastante transformado, hasta su progresiva extinciâ”œâ”‚n no natural en la segunda mitad del siglo XX. Asâ”œÂ¡, y de izquierda a derecha, el hotelito del nâ”¬â•‘ 1 diseâ”œâ–’ado por Antonio Miranda y ya transformado por Fernando de Yarza Fernâ”œÃ­ndez-Treviâ”œâ–’o para el industrial Tomâ”œÃ­s Castellano Villarroya. Los hotelitos nâ”¬â•‘ 2, 3 y 4 aquâ”œÂ¡ se muestran como lo que fueron en un principio: idâ”œÂ®nticas viviendas unifamiliares proyectadas de forma seriada por Fâ”œÂ®lix Navarro Pâ”œÂ®rez. Tras la calle de Puigcerdâ”œÃ­, el hotelito del nâ”¬â•‘ 5, proyectado por Manuel Ruiz; el nâ”¬â•‘ 6, proyectado por Eusebio Lidâ”œâ”‚n Barra, ya recrecido en una altura respecto al original; finalmente y a la derecha, vista parcial del nâ”¬â•‘ 7, proyectado por Fernando de Yarza Fernâ”œÃ­ndez-Treviâ”œâ–’o en aires inequâ”œÂ¡vocamente franceses. A la izquierda y tras la calle de Juan Bruil, la gran estructura del Teatro Pignatelli, por encima del que sobresale la â”œâ•‘nica torre de la iglesia parroquial de Santa Engracia, y tras la homâ”œâ”‚nima plaza, vista de la gran casa del conde de La Rosa.', 1893, 1893, 1893, 'Siglo XIX', 'CENTRO', 41.64836800, -0.88486000, '0101000020E6100000E23B31EBC550ECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50086764277.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50086764277.webp', 'https://www.flickr.com/photos/zaragozaantigua/50086764277/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21191, 'Glorieta de Pignatelli c.1890', 'Imagen capturada en la glorieta de Pignatelli y centrada en el homâ”œâ”‚nimo monumento que desde 1859 lucâ”œÂ¡a en este espacio que jalonaba la direcciâ”œâ”‚n del ensanche de la ciudad por el sur. Hacia el fondo y en perspectiva, edificaciones del paseo de la Independencia, a la izquierda los que pretendâ”œÂ¡an rememorar la parisina y porticada "rue de Rivoli", y a la derecha el tramo que hasta la plaza de Santa Engracia determinaba la grâ”œÃ­cil estructura del Teatro Pignatelli, y que mâ”œÃ­s allâ”œÃ­ culmina el remate de la barroca torre de la Seo. En primer tâ”œÂ®rmino y a la derecha, un auxiliar del fotâ”œâ”‚grafo aparta sutilmente con una gayata unos juncales para despejar la vista de la base del monumento, aunque para ello se mete en el encuadre resultando asâ”œÂ¡ una estampa muy zaragozana.', 1890, 1890, 1890, 'Siglo XIX', 'CENTRO', 41.64838400, -0.88485000, '0101000020E6100000FFB27BF2B050ECBFF59F353FFED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50120055002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50120055002.webp', 'https://www.flickr.com/photos/zaragozaantigua/50120055002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21270, 'Plaza de Aragâ”œâ”‚n 1903', 'Imagen de la plaza de Aragâ”œâ”‚n cuando el inquilino ilustrado, Don Ramâ”œâ”‚n Pignatelli, estaba apurando el contrato de permanencia, antes de deslocalizarse Paseo de Sagasta arriba, y ser sustituido por otro inquilino, este sedente, y medieval. Detrâ”œÃ­s, la calle de la Independencia y la plaza de Santa Engracia. Delante, un muchacho comenzando la carrera de Don Tancredo. Fuente visual: Postal de la colecciâ”œâ”‚n &quot;Aragâ”œâ”‚n&quot;, serie &quot;Zaragoza&quot; (nâ”¬â•‘ 14, Estatua de Pignatelli) del librero Cecilio Gasca. Huecograbado impreso en color azul.', 1903, 1903, 1903, 'Anos 1900', 'CENTRO', 41.64836500, -0.88495900, '0101000020E6100000AEA069899551ECBF7E6FD39FFDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21923194505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21923194505.webp', 'https://www.flickr.com/photos/zaragozaantigua/21923194505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21289, 'Glorieta de Pignatelli c.1900', 'Tarjeta postal centrada en el edificio de la nueva Capitanâ”œÂ¡a General sito en la glorieta de Pignatelli. A la izquierda, el paseo de le Lealtad. A la derecha, uno de los hotelitos edificado sobre los terrenos de la Exposiciâ”œâ”‚n Aragonesa de 1885. Fuente: Fototipia Hauser y Menet, en www.ebay.es/', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64816800, -0.88569700, '0101000020E61000003C4A253CA157ECBF2828452BF7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26544808425.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26544808425.webp', 'https://www.flickr.com/photos/zaragozaantigua/26544808425/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21353, 'Glorieta de Pignatelli 1900', 'Luminosa imagen capturada en la glorieta de Pignatelli cuando esta seguâ”œÂ¡a siendo la principal zona verde de la ciudad. Fue trazada en 1840 en este espacio de transiciâ”œâ”‚n entre el Salâ”œâ”‚n de Santa Engracia y la puerta y puente homâ”œâ”‚nimos, vertebrada como ilustra la fotografâ”œÂ¡a en torno a la estatua del prâ”œâ”‚cer local Ramâ”œâ”‚n Pignatelli tallada por Antonio Palao Marco e inaugurada en 1859. Tras la Exposiciâ”œâ”‚n Aragonesa de 1868 que se ubicâ”œâ”‚ aquâ”œÂ¡, el terreno fue distribuido en manzanas cuyos solares terminaron vendidos, por causa de la mala situaciâ”œâ”‚n econâ”œâ”‚mica del Ayuntamiento, a algunas de las familias mâ”œÃ­s poderosas de la ciudad que construyeron en este selecto espacio destacados hotelitos particulares. En la escena puede verse a la derecha el hotelito de Tomâ”œÃ­s Castellano Villarroya y dos de los hotelitos pareados proyectados por Fâ”œÂ®lix Navarro Pâ”œÂ®rez. Al fondo y de izquierda a derecha, edificios de la calle de la Independencia, el Teatro Pignatelli y la iglesia de Santa Engracia con su torre lateral reconstruida poco antes.', 1900, 1900, 1900, 'Anos 1900', 'CENTRO', 41.64814400, -0.88510700, '0101000020E6100000D3BD4EEACB52ECBFA08CF161F6D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54773818688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54773818688.webp', 'https://www.flickr.com/photos/zaragozaantigua/54773818688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21399, 'Calle de Valencia 1913', 'Imagen de postal capturada desde la cima de la Facultad de Medicina, que entonces era atalaya privilegiada para contemplar los tejados de la ciudad. La visual estâ”œÃ­ orientada hacia el el noreste, siguiendo la lâ”œÂ¡nea que marca la calle de Valencia (luego, Bilbao), hasta Casa Jimâ”œÂ®nez, con el edificio de Capitanâ”œÂ¡a General a la derecha, y la fâ”œÃ­brica de conservas "Bescâ”œâ”‚s Hermanos" a la izquierda. Esta fâ”œÃ­brica "a vapor" estaba especializada en "artâ”œÂ¡culos finos para fondas y restaurantes", cuando en la ciudad habâ”œÂ¡a una destacada nâ”œâ”‚mina de este tipo de factorâ”œÂ¡as (Delatas y Compaâ”œâ–’â”œÂ¡a, Antonio Burillo, Cortâ”œÂ®s Gusâ”œÂ® y Câ”œÂ¡a, Manuel Marraco...) A la derecha, y en paralelo, tras la plaza de Aragâ”œâ”‚n, el arbolado paseo de la Independencia, en el tramo de la plaza de Santa Engracia, con el palacete del barâ”œâ”‚n de la Rosa a un lado, y los nuevos porches del paseo aâ”œâ•‘n sin el previsto edificio de Correos encima, al otro. Al fondo, La Seo, San Gil, y el Pilar. Fuente visual: Lucien Levy fils.', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64818600, -0.88611400, '0101000020E610000047E350BF0B5BECBFCFDC43C2F7D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21593018713.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21593018713.webp', 'https://www.flickr.com/photos/zaragozaantigua/21593018713/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21403, 'Conservas Bescâ”œâ”‚s 1910', 'Imagen publicitaria de la fâ”œÃ­brica de conservas vegetales de Mariano Bescâ”œâ”‚s, luego Bescâ”œâ”‚s Hermanos, que se instalâ”œâ”‚ en Zaragoza hacia 1900, permaneciendo allâ”œÂ¡ durante mâ”œÃ­s de tres dâ”œÂ®cadas. En el centro del dibujo, la factorâ”œÂ¡a del paseo de Pamplona, entre las calles de Ponciano Ponzano y Bilbao. Fuente visual: www.todocoleccion.net', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.64827900, -0.88635300, '0101000020E610000082C476F7005DECBF80D767CEFAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23975209680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23975209680.webp', 'https://www.flickr.com/photos/zaragozaantigua/23975209680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21437, 'Plaza Aragâ”œâ”‚n 1915', 'Paso por el ala oeste de la plaza de Aragâ”œâ”‚n de la carroza del Ayuntamiento de Zaragoza, precedida de niâ”œâ–’os exploradores con sus banderas y singulares sombreros, en el desfile de las fiestas del Pilar de 1915.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64873900, -0.88487000, '0101000020E6100000C6C4E6E3DA50ECBFE3512AE109D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43360932091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43360932091.webp', 'https://www.flickr.com/photos/zaragozaantigua/43360932091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21452, 'Plaza de Aragâ”œâ”‚n 1915', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 13 de la plaza de Aragâ”œâ”‚n con una interesante vista de este tradicional espacio urbano de esparcimiento. De la frondosa isleta central emerge el Monumento al Justiciazgo, y al otro lado de la plaza se nos muestra el tramo edilicio desde la calle de Puigcerdâ”œÃ­, a la izquierda, con una vista completa de los "hotelitos" de los nâ”œâ•‘meros 5 a 8. Tras ellos la trinchera del râ”œÂ¡o Huerva y el gran edificio del colegio del Salvador. A la derecha y al fondo, la facultad de Medicina y Ciencias junto al puente de Santa Engracia que da acceso al paseo de Sagasta.', 1915, 1915, 1915, 'Anos 10', 'CENTRO', 41.64897700, -0.88482800, '0101000020E61000000AB952CF8250ECBF986DA7AD11D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51696244542.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51696244542.webp', 'https://www.flickr.com/photos/zaragozaantigua/51696244542/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21518, 'Calle de Bilbao 1922', 'Archivo Burges. 1922. "Juegos Olâ”œÂ¡mpicos" organizados por la FASD (Federaciâ”œâ”‚n Aragonesa de Sociedades Deportivas), con el objetivo de abarcar a todo el territorio regional, e integrar a todos los deportes, en el campo de fâ”œâ•‘tbol de la calle de Bilbao. Su vida serâ”œÃ­ breve. En la imagen, prueba de salto de altura de esos "Juegos Olâ”œÂ¡mpicos". Al fondo, edificios de la calle Bilbao: las viviendas, a la derecha (superviven), y las instalaciones del Gobierno Militar en el antiguo Convento de las Descalzas de San Josâ”œÂ®, a la izquierda (superviven, como instalaciones municipales). Fuente: Pedro Ciria Amores "El sueâ”œâ–’o de ser grandes: Historia social del nacimiento del fâ”œâ•‘tbol en Zaragoza, 1903-1936".', 1922, 1922, 1922, 'Anos 20', 'CENTRO', 41.64953000, -0.88592200, '0101000020E610000039D219187959ECBFACE28DCC23D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15943587556.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15943587556.webp', 'https://www.flickr.com/photos/zaragozaantigua/15943587556/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23996, 'Base Aâ”œÂ®rea 2003', 'Foto: Javier Belver Pese a que en 1992 las fuerzas armadas estadounidenses abandonaron oficialmente la Base Aâ”œÂ®rea de Zaragoza, â”œÂ®sta siguiâ”œâ”‚ ofreciendo apoyo logâ”œÂ¡stico al ejâ”œÂ®rcito de ese paâ”œÂ¡s. En la imagen, una marcha convocada como protesta en el marco de la Guerra de Irak, el 30 de marzo de 2003. Fuente: European Pressphoto Agency.', 2003, 2003, 2003, 'Siglo XXI', NULL, 41.66578500, -1.06859900, '0101000020E6100000E59CD843FB18F1BF6C95607138D54440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20876334941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20876334941.webp', 'https://www.flickr.com/photos/zaragozaantigua/20876334941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21569, 'Plaza de Aragâ”œâ”‚n c.1920', 'Los dâ”œÂ¡as de niebla (en cualquiera de sus denominaciones) en Zaragoza son bastantes introspectivos, como ensimismados. El aire frâ”œÂ¡o y hâ”œâ•‘medo, sin circulaciâ”œâ”‚n atmosfâ”œÂ®rica que lo perturbe, en ocasiones parece empadronarse, y nos acompaâ”œâ–’a varias jornadas. Es un fenâ”œâ”‚meno que ralentiza el tiempo, como la imagen ilustra, en una apacible maâ”œâ–’ana de la plaza de Aragâ”œâ”‚n, cuando un tranquilo paseo sintoniza con el silencio apenas alterado por palabras susurradas. El paisaje urbano se difumina, sus perfiles se suavizan, y la ciudad se acurruca en sâ”œÂ¡ misma, en el fondo, y en la forma. Al fondo, en el paseo de la Independencia, los ecos del traqueteo tranviario resuenan leves, como entre algodones. Fuente visual: Archivo Julio Requejo (DARA-AHPZ)', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64841500, -0.88489300, '0101000020E6100000D1B2EE1F0B51ECBF309E4143FFD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23632887120.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23632887120.webp', 'https://www.flickr.com/photos/zaragozaantigua/23632887120/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21594, 'General Sanjurjo 1926', 'El 12 de octubre de 1926, la Dictadura de Primo de Rivera decretâ”œâ”‚ la celebraciâ”œâ”‚n de la "Fiesta de la Paz y Homenaje al Ejâ”œÂ®rcito", por el feliz tâ”œÂ®rmino de las campaâ”œâ–’as de Marruecos. En Zaragoza, la coincidencia con el dâ”œÂ¡a de la Virgen del Pilar, reforzâ”œâ”‚ aâ”œâ•‘n mâ”œÃ­s los lazos "Pilar, Raza, Patria". Ese dâ”œÂ¡a visitaron la ciudad los generales Primo de Rivera, Sanjurjo, ademâ”œÃ­s de varios ministros y personalidades, protagonizando una apretada agenda de actos que comenzâ”œâ”‚ de buena maâ”œâ–’ana con un solemne "Tedâ”œÂ®um" en el Pilar, y un responso "por los muertos de â”œÃ¼frica" (los propios). Acto seguido, la comitiva se dirigiâ”œâ”‚ a la hasta entonces calle de la Soberanâ”œÂ¡a Nacional, para descubrir una lâ”œÃ­pida que escenificaba el cambio de su nomenclâ”œÃ­tor por "General Sanjurjo", que ademâ”œÃ­s recibiâ”œâ”‚ el tâ”œÂ¡tulo de "Hijo Adoptivo de Zaragoza". En la imagen, descubierta lâ”œÃ­pida de la nueva calle, tallada de forma singular, sobre los muros del Cuartel del Carmen, en la esquina de la antigua Soberanâ”œÂ¡a Nacional-nueva General Sanjurjo. Con la llegada de la democracia, en 1931, esta calle recuperâ”œâ”‚ su denominaciâ”œâ”‚n anterior, aunque tras el 18 de julio de 1936, la Soberanâ”œÂ¡a Nacional fue desaparecida por segunda vez (signo de los tiempos), siendo sustituida nuevamente por el General Sanjurjo, en el tramo desde la puerta del Carmen a Ramâ”œâ”‚n y Cajal, y aâ”œâ–’os despuâ”œÂ®s por el blaudivisionario en Rusia, Capitâ”œÃ­n Portolâ”œÂ®s, en el tramo hasta la plaza del Carmen. Fuente visual: Alejandro de la Barrera, Archivo Municipal de Zaragoza.', 1926, 1926, 1926, 'Anos 20', 'CENTRO', 41.65087900, -0.88485900, '0101000020E6100000CB4752D2C350ECBF9C53C90050D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24873795905.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24873795905.webp', 'https://www.flickr.com/photos/zaragozaantigua/24873795905/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21696, 'Plaza de Aragâ”œâ”‚n Aâ”œâ–’os 30', 'AHPZ. Estudio Coyne. Aâ”œâ–’os 30. La plaza de Aragâ”œâ”‚n fue diseâ”œâ–’ada con planta de "parâ”œÂ®ntesis", con estatua en medio; Pignatelli, primero, Lanuza, luego. En la imagen, aspecto del parâ”œÂ®ntesis izquierdo (desde el punto de vista de esta imagen) del que arranca la calle Canfranc (hacia la izquierda), y los hotelitos que la mojoneaban, hasta que fueron (menos uno) procesados dâ”œÂ®cadas despuâ”œÂ®s por la piqueta del capitalismo de nuevo signo, vertical, imponente, despiadado.', 1930, 1930, 1939, 'Anos 30', 'CENTRO', 41.64846400, -0.88537500, '0101000020E6100000A245B6F3FD54ECBF11514CDE00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15377547151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15377547151.webp', 'https://www.flickr.com/photos/zaragozaantigua/15377547151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21732, 'Calle Albareda 1933', 'El 26 de junio de 1933 el Frontâ”œâ”‚n Aragonâ”œÂ®s fue escenario de un mitin convocado por el partido "Comuniâ”œâ”‚n Tradicionalista de Zaragoza". Lleno a rebosar con tradicionalistas de toda la provincia, amenizaba la tradicionalista banda de Novallas. Presentâ”œâ”‚ el acto Jesâ”œâ•‘s Comâ”œÂ¡n, dando paso al diputado en Cortes, Josâ”œÂ® Lamamiâ”œÂ® de Clairac, terrateniente salmantino, catâ”œâ”‚lico, carlista, y tradicionalista de derechas, que seâ”œâ–’alâ”œâ”‚ que la soluciâ”œâ”‚n â”œâ•‘nica a los problemas estaba en la doctrina catâ”œâ”‚lica. Hablâ”œâ”‚ despuâ”œÂ®s Mâ”¬Â¬ Rosa Urraca, seâ”œâ–’orita que apuntâ”œâ”‚ que la obra para erradicar la amenaza revolucionaria, estaba ya en marcha. Finalmente, Esteban Bilbao recordâ”œâ”‚ los tres principios de la Espaâ”œâ–’a tradicional: el altar (dios), la bandera (patria), y el Trono (rey). A la salida del mitin, se produjeron disturbios resultando 13 heridos de diversa consideraciâ”œâ”‚n, y varios detenidos. En la imagen, la calle de Albareda con tradicionalistas filas para acceder al novâ”œÂ¡simo frontâ”œâ”‚n Aragones. Al fondo, el paseo de la Independencia. A la izquierda, los muros del Gobierno Militar, antiguo convento de las Carmelitas Descalzas de San Josâ”œÂ®. Fuente visual: Foto Martâ”œÂ¡nez, "Mundo Grâ”œÃ­fico".', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64949800, -0.88518200, '0101000020E61000007D40A0336953ECBFA1681EC022D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21327145723.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21327145723.webp', 'https://www.flickr.com/photos/zaragozaantigua/21327145723/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21860, 'Pl. de Aragâ”œâ”‚n 1933', 'Imagen capturada en la arbolada plaza de Aragâ”œâ”‚n y centrada en el ambulante ciclista-afilador Soriano, pionero emprendedor del maridaje entre el moderno deporte del ciclismo y el antiguo oficio del vaciado de navajas, cuchillos y tijeras. La bicicleta permite transportar las piedras de amolar y derivar, sin excesivo esfuerzo, la fuerza motriz que requiere el giro en altura (sin rozamiento con el suelo) de la rueda trasera. La sencillez del proceso era inversamente proporcional al eco y expectaciâ”œâ”‚n que despertaba a su paso, de forma especial cuando era llamado para un servicio y paraba a realizarlo de forma inmediata en la misma calle o plaza en que se encontrara. De forma automâ”œÃ­tica, como por ensalmo, y sin necesidad de convocatoria previa, una nutrida parroquia se congregaba para asistir al evento gratis et amore. Hoy en dâ”œÂ¡a, muy ocasionalmente, es posible ver en la ciudad algâ”œâ•‘n afilador que se anuncia con su caracterâ”œÂ¡stico chiflo o pequeâ”œâ–’a flautilla. Este sonido, cuando consigue dejarse oâ”œÂ¡r entre el estrâ”œÂ®pito del urbano trâ”œÃ­nsito motorizado, mantiene un atâ”œÃ­vico efecto de llamada y atracciâ”œâ”‚n irresistible e incomprensible para el postmoderno, o postmoderna. Fuente visual: www.mecd.gob.es/.', 1933, 1933, 1933, 'Anos 30', 'CENTRO', 41.64838600, -0.88523500, '0101000020E610000032C9C859D853ECBF9697FC4FFED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36262596111.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36262596111.webp', 'https://www.flickr.com/photos/zaragozaantigua/36262596111/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21976, 'Plaza Aragâ”œâ”‚n 1944', 'Proyecto no realizado para la â”œâ•‘ltima reforma integral del hotelito del nâ”œâ•‘mero 12 de la plaza de Aragâ”œâ”‚n, que fue ampliando su tamaâ”œâ–’o de 1868 a 1944, quedâ”œÃ­ndose sin las dos filas laterales previstas en el dibujo, aunque sâ”œÂ¡ elevando su altura como se mostraba. Hoy es el â”œâ•‘nico edificio primigenio conservado, y alberga un restaurante de lujo. Fuente: Estudio Coyne. DARA/AHPZ.', 1944, 1944, 1944, 'Anos 40', 'CENTRO', 41.64900000, -0.88511900, '0101000020E6100000E42EC214E552ECBF508D976E12D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24914495539.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24914495539.webp', 'https://www.flickr.com/photos/zaragozaantigua/24914495539/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24745, 'Calle del Sobrarbe 1891', 'Aspecto de la calle del Sobrarbe, con la iglesia de Nâ”¬Â¬ Sâ”¬Â¬ de Altabâ”œÃ­s en construcciâ”œâ”‚n, inaugurada un aâ”œâ–’o despuâ”œÂ®s.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HISTâ”œÃ´RICO', 41.65822000, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15674320287.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15674320287.webp', 'https://www.flickr.com/photos/zaragozaantigua/15674320287/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21981, 'Pl. de Basilio Paraâ”œÂ¡so c.1942', 'Vista editada como postal por Garcâ”œÂ¡a Garrabella. La panorâ”œÃ­mica, con la plaza de Paraâ”œÂ¡so a los pies, se hizo en altura desde la cima del (edificio) Elâ”œÂ¡seos, erigido en el arranque del paseo del general Mola. Un poco mâ”œÃ­s al frente, la plaza de Aragâ”œâ”‚n y el entronque con la arboleda del paseo de la Independencia. Hacia la derecha, el paseo de Marina Moreno. Hacia la izquierda, el paseo de Pamplona. En la plaza de Paraâ”œÂ¡so estaba empadronado el primaporteâ”œâ–’o câ”œÂ®sar donado por Mussolini, aunque ya en "modo espera", pendiente de una reubicaciâ”œâ”‚n mâ”œÃ­s imperial en la zona de la muralla de piedra, romana e islâ”œÃ­mica, junto al alcâ”œÃ­zar de la Sudda. Da la sensaciâ”œâ”‚n de que la instalaciâ”œâ”‚n de la preciosa fuente luminosa, amable y desinteresadamente donada en la siguiente dâ”œÂ®cada, supuso que antes hubiera que hacerse una apreciable escarda de â”œÃ­rboles que despejara la visual para el trâ”œÃ­fico motorizado. Para â”œÃ­rboles, ya estaba el parque Primo de Rivera, y lo primero, es lo primero. Al fondo, la ciudad. Fuente: www.todocoleccion.net/', 1942, 1942, 1942, 'Anos 40', 'CENTRO', 41.64849400, -0.88480900, '0101000020E61000005A9BC6F65A50ECBF7CD3F4D901D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25572979586.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25572979586.webp', 'https://www.flickr.com/photos/zaragozaantigua/25572979586/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21988, 'Plaza de Aragâ”œâ”‚n 1949', 'Imagen de la antigua plaza de Aragâ”œâ”‚n como espacio donde poder disfrutar del sol de invierno, apreciado por la chiquillerâ”œÂ¡a como si de un parque se tratara. Al fondo, a la izquierda, la casa de Luis Pâ”œÂ®rez Cistuâ”œÂ® que unos aâ”œâ–’os antes habâ”œÂ¡a sido muy reformada, y recrecida en vertical. Al fondo, y a la derecha, las solaneras de las desaparecidas casonas recayentes a la calle Albareda. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.64873900, -0.88487000, '0101000020E6100000C6C4E6E3DA50ECBFE3512AE109D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30287910596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30287910596.webp', 'https://www.flickr.com/photos/zaragozaantigua/30287910596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22019, 'Los sombrâ”œÂ¡os aâ”œâ–’os 40', 'El jueves 27 de febrero (festividad de San Gabriel de la Dolorosa) del aâ”œâ–’o en curso 2020, a las 19 horas y en la sala Pilar Sinuâ”œÂ®s del Edificio Paraninfo de la Universidad de Zaragoza (plaza de Basilio Paraâ”œÂ¡so nâ”¬â•‘ 4), tendrâ”œÃ­ lugar el acto de presentaciâ”œâ”‚n del libro "Memoria visual de Zaragoza. Los sombrâ”œÂ¡os aâ”œâ–’os 40", editado por El Periâ”œâ”‚dico de Aragâ”œâ”‚n. Entrada libre hasta completar aforo. Abstenerse desaforados (en su primera acepciâ”œâ”‚n). El acto contarâ”œÃ­ con la presencia de Nicolâ”œÃ­s Espada, director de El Periâ”œâ”‚dico de Aragâ”œâ”‚n, y de los autores del libro, Josâ”œÂ® Marâ”œÂ¡a Ballestâ”œÂ¡n Miguel y Antonio Tausiet, del Gran Archivo Zaragoza Antigua (GAZA). Previsiblemente, no contaremos con presencia de concejales de aquellos aâ”œâ–’os, ni de estos actuales. En la imagen, portada del libro, aspecto en altura de la antigua plaza de Aragâ”œâ”‚n de toda la vida. Foto Estudio Coyne (AHPZ), coloreada de forma inâ”œÂ®dita para la ocasiâ”œâ”‚n.', 1940, 1940, 1949, 'Anos 40', 'CENTRO', 41.64843900, -0.88493500, '0101000020E61000008CBE82346351ECBFB939950C00D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49557421926.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49557421926.webp', 'https://www.flickr.com/photos/zaragozaantigua/49557421926/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25606, 'Condes de Aragâ”œâ”‚n 1973', 'Cosecha en el Polâ”œÂ¡gono Gran Vâ”œÂ¡a. La progresiva urbanizaciâ”œâ”‚n de este entorno supuso la apertura de nuevos viales, algunos de ellos fronteros con una periferia agrâ”œÂ¡cola productiva desde siglos antes, en el mâ”œÃ­s antiguo tâ”œÂ®rmino de Romareda, desde el siglo XII, y el tâ”œÂ®rmino de Almotilla, desde el siglo XIV. En la imagen, cosechadora francesa Braud 405 en plena faena en un campo de cereal con el fondo edilicio del nâ”¬â•‘ 23 de la calle de los Condes de Aragâ”œâ”‚n, casi terminado, al igual que su vecino del nâ”¬â•‘ 26-C de la calle de Asâ”œÂ¡n y Palacios, a la izquierda.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.63742400, -0.90727300, '0101000020E6100000E066F1626108EDBFBFD7101C97D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16225764972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16225764972.webp', 'https://www.flickr.com/photos/zaragozaantigua/16225764972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22246, 'Calle del General Sanjurjo c.1956', 'Imagen capturada en el interior de la iglesia del Carmen Calzado o de los carmelitas Calzados sita en el nâ”œâ•‘mero 7 de la calle del General Sanjurjo. El esplâ”œÂ®ndido y gran convento carmelita Calzado del Carmen quedâ”œâ”‚ arruinado tras los episodios bâ”œÂ®licos de 1808-1813, aunque luego se reconstruyeron la iglesia, convento y colegio de San Josâ”œÂ® con su iglesia. En 1836 el conjunto fue desamortizado y, al no encontrar postor, quedâ”œâ”‚ en manos pâ”œâ•‘blicas, cediendo parte de sus instalaciones para cuartel del ramo de la Guerra, inclusa de niâ”œâ–’os expâ”œâ”‚sitos, casa de monta, escuela de Veterinaria, cuartel de la Guardia Civil y depâ”œâ”‚sito de cadâ”œÃ­veres. En 1938 la iglesia fue habilitada por los nacionalistas, a travâ”œÂ®s del Servicio de Defensa del Patrimonio Artâ”œÂ¡stico Nacional, como almacâ”œÂ®n o depâ”œâ”‚sito provisional de obras artâ”œÂ¡sticas religiosas "abandonadas por la rapiâ”œâ–’a roja en su huida" (sic). En 1948 los carmelitas calzados volvieron a ocupar la antigua Iglesia del noviciado, dotâ”œÃ­ndola de culto, que fue bendecida e inaugurada por el arzobispo Rigoberto Domenech Valls, convirtiâ”œÂ®ndose en templo muy frecuentado. Aâ”œâ–’os despuâ”œÂ®s comenzaron las obras del proyectado ensanchamiento de la calle del General Sanjurjo para convertirla en parte de la nueva Vâ”œÂ¡a Imperial. De esta forma, en 1964 esta iglesia fue definitivamente derribada.', 1956, 1956, 1956, 'Anos 50', 'CENTRO', 41.65037200, -0.88666300, '0101000020E61000000C5872158B5FECBFF71DC3633FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51710073433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51710073433.webp', 'https://www.flickr.com/photos/zaragozaantigua/51710073433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22254, 'Plaza de Aragâ”œâ”‚n 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/1966. El Real Zaragoza se jugaba los octavos de final de la "Copa de Ferias" con el escocâ”œÂ®s equipo del Heart of Midlothian, y la eliminatoria era a dos partidos (ida, y vuelta). En ambos encuentros terminaron empatados, y las normas decâ”œÂ¡an que para desempatar era preciso un tercer encuentro, en Zaragoza. En la imagen, la plantilla del equipo escocâ”œÂ®s, de civil, visitando la ciudad, y hay que agradecerles el buen gusto del posado de la imagen, precisamente en la Plaza de Aragâ”œâ”‚n, para asâ”œÂ¡ tener una buena panorâ”œÃ­mica de los edificios del fondo, en el lado de los nâ”œâ•‘meros 9 a 13. De izquierda a derecha, la base del monumento a Juan de Lanuza, y un pedazo del nâ”¬â•‘ 9, la entonces Capitanâ”œÂ¡a General de la Vâ”¬Â¬ Regiâ”œâ”‚n Militar, construida en 1893, y que perdura, aunque ya no como Capitanâ”œÂ¡a General. Luego, el nâ”¬â•‘ 10, esquina con calle Canfranc, desaparecido. Sigue un pedazo del nâ”¬â•‘ 11, en la otra esquina con la calle Canfranc, desaparecido. Por supuesto que el fâ”œâ•‘tbol es interesante.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64840000, -0.88479600, '0101000020E6100000333674B33F50ECBFFB5C6DC5FED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664561560.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664561560.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664561560/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25628, 'Paseo isabel la Catâ”œâ”‚lica 2009', 'Foto: Oliver Duch. Vista del paseo de Isabel la Catâ”œâ”‚lica, tomada con motivo del inicio de las obras de la lâ”œÂ¡nea 1 del tranvâ”œÂ¡a, el lunes 21 de septiembre de 2009. Centra la imagen el edificio de la central tecnolâ”œâ”‚gica de la Caja de Ahorros de la Inmaculada, obra de Josâ”œÂ® Manuel Pâ”œÂ®rez Latorre. La toma se extiende hacia el norte, permitiendo contemplar la câ”œâ•‘pula de la iglesia de Santiago, la chimenea y la contaminaciâ”œâ”‚n de Saica, en el Picarral, el Pilar y las chimeneas de la azucarera del Arrabal. Fuente: Heraldo de Aragâ”œâ”‚n.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.63690300, -0.89922600, '0101000020E61000000BD0B69A75C6ECBFB5DC990986D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33069676702.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33069676702.webp', 'https://www.flickr.com/photos/zaragozaantigua/33069676702/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22255, 'Plaza de Aragâ”œâ”‚n 1966', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo/1966. El Real Zaragoza se jugaba los octavos de final de la "Copa de Ferias" con el escocâ”œÂ®s equipo del Heart of Midlothian, y la eliminatoria era a dos partidos (ida, y vuelta). En ambos encuentros terminaron empatados, y las normas decâ”œÂ¡an que para desempatar era preciso un tercer encuentro, en Zaragoza. En la imagen, la plantilla del equipo escocâ”œÂ®s, de civil, visitando la ciudad, y hay que agradecerles el buen gusto del posado de la imagen, precisamente en la Plaza de Aragâ”œâ”‚n, para asâ”œÂ¡ tener una buena panorâ”œÃ­mica de los edificios del fondo, en el lado de los nâ”œâ•‘meros 9 a 13. En la imagen, un pedazo del nâ”¬â•‘ 11, desaparecido luego. Sigue el nâ”¬â•‘ 12, construido en 1888, que perdura. Finalmente, el nâ”¬â•‘ 13, esquina con Albareda, desaparecido. Entre el 11 y el 13 vemos las traseras del nâ”¬â•‘ 5 de la calle Ponzano, hoy ocultas por la mole del nuevo nâ”¬â•‘ 13 de la Plaza de Aragâ”œâ”‚n. Por supuesto que el fâ”œâ•‘tbol es interesante.', 1966, 1966, 1966, 'Anos 60', 'CENTRO', 41.64836800, -0.88475300, '0101000020E610000061360186E54FECBFEFE2FDB8FDD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14664737017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14664737017.webp', 'https://www.flickr.com/photos/zaragozaantigua/14664737017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22275, 'Puerta del Carmen 1968', 'Ayuntamiento de Zaragoza. Gerardo Sancho Ramo. 18/05/1968. "Vista de la calle Cesar Augusto en obras." Al fondo, la Puerta del Carmen va a quedar bien despejada de edificios, â”œÃ­rboles, y cosas para que la Vâ”œÂ¡a Imperial llegue desde el Ebro. Los modestos edificios de la izquierda ilustran lo limitados de miras que eran nuestros ancestros, que en lugar de avenidas, hacâ”œÂ¡an calles, y en lugar de bloques, parcelas. Afortunadamente, el progreso estaba llegando para poner a cada uno en su sitio, y a los coches, en todas partes.', 1968, 1968, 1968, 'Anos 60', 'CENTRO', 41.65103800, -0.88619100, '0101000020E61000001E4E603AAD5BECBF043A933655D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14962135362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14962135362.webp', 'https://www.flickr.com/photos/zaragozaantigua/14962135362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22481, 'P.â”¬â•‘ de Pamplona 1967', 'Imagen capturada en arranque del paseo de Pamplona durante el paso de la banda de mâ”œâ•‘sica de la 8.â”¬Â¬ Divisiâ”œâ”‚n de Infanterâ”œÂ¡a del ejâ”œÂ®rcito de los Estados Unidos de Amâ”œÂ®rica del Norte con motivo de su participaciâ”œâ”‚n de las Fiestas de Primavera, tambiâ”œÂ®n denominadas Coso Blanco, de ese aâ”œâ–’o. Al fondo, a la izquierda, despunta la torre de la iglesia de la Madre del Salvador de los PP. Jesuitas. En el centro, el colegio del Sagrado Corazâ”œâ”‚n y la gran mole del edificio Elâ”œÂ¡seos rematado con su publicitaria peineta. A la derecha, la facultad de Medicina y Ciencias de la Universidad y el comienzo de los nâ”œâ•‘meros impares del paseo, con interesante vista del antiguo nâ”¬â•‘ 5. Fuente visual: Jarke/Jaria, AMZ.', 1967, 1967, 1967, 'Anos 60', 'CENTRO', 41.64831400, -0.88668300, '0101000020E6100000D369DD06B55FECBFFCC401F4FBD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38521374621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38521374621.webp', 'https://www.flickr.com/photos/zaragozaantigua/38521374621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
